#!/usr/bin/env python3
"""
generar_dashboard.py
Lee un Excel con hojas PYG, PRESUPUESTO y CANALES
y genera un dashboard HTML interactivo completo.

Uso:
    python generar_dashboard.py                          # Excel por defecto
    python generar_dashboard.py datos.xlsx               # Excel personalizado
    python generar_dashboard.py datos.xlsx -n "Mi Empresa" -o reporte.html -m USD
"""
import sys, os, re, json, argparse
from pathlib import Path

try:
    import openpyxl
except ImportError:
    print("❌ Falta openpyxl.  pip install openpyxl")
    sys.exit(1)

# ─── LECTURA EXCEL ────────────────────────────────────────────────────────────

MESES_MAP = {
    'ENERO':'Ene','FEBRERO':'Feb','MARZO':'Mar','ABRIL':'Abr',
    'MAYO':'May','JUNIO':'Jun','JULIO':'Jul','AGOSTO':'Ago',
    'SEPTIEMBRE':'Sep','OCTUBRE':'Oct','NOVIEMBRE':'Nov','DICIEMBRE':'Dic',
}

def norm_mes(v):
    if v is None: return None
    return MESES_MAP.get(str(v).strip().upper(), None)

def find_col(ws, row, fragment):
    for cell in ws[row]:
        if cell.value and fragment.upper() in str(cell.value).upper():
            return cell.column
    return None

def leer_pyg(wb):
    ws = next((wb[n] for n in wb.sheetnames if 'PYG' in n.upper()), None)
    if not ws: raise ValueError("No se encontró hoja PYG")
    cols = dict(
        ventas    = find_col(ws,1,'VENTA'),
        costo     = find_col(ws,1,'COSTO'),
        util_b    = find_col(ws,1,'UTILIDAD BRUTA'),
        gastos_op = find_col(ws,1,'GASTOS'),
        gtos_no   = find_col(ws,1,'NO OPER'),
    )
    if cols['gtos_no'] is None:
        cols['gtos_no'] = find_col(ws,1,'INGRESOS NO')
    d = {k:[] for k in ['meses','ventas','costo','util_b','gastos_op','gtos_no']}
    for row in ws.iter_rows(min_row=2, values_only=True):
        m = norm_mes(row[0])
        if not m: continue
        def v(k): return round((row[cols[k]-1] or 0)/1e6, 1) if cols[k] else 0.0
        d['meses'].append(m)
        d['ventas'].append(v('ventas'))
        d['costo'].append(v('costo'))
        d['util_b'].append(v('util_b'))
        d['gastos_op'].append(v('gastos_op'))
        d['gtos_no'].append(v('gtos_no'))
    if not d['meses']: raise ValueError("PYG sin datos")
    return d

def leer_ppto(wb, pyg):
    ws = next((wb[n] for n in wb.sheetnames if 'PRESUPUESTO' in n.upper()), None)
    if not ws: return pyg['ventas'][:]
    col = find_col(ws,1,'PRESUPUESTO') or 2
    out = []
    for row in ws.iter_rows(min_row=2, values_only=True):
        if norm_mes(row[0]):
            out.append(round((row[col-1] or 0)/1e6, 1))
    return out if out else pyg['ventas'][:]

def leer_canales(wb):
    ws = next((wb[n] for n in wb.sheetnames if 'CANAL' in n.upper()), None)
    if not ws: return []
    cols = dict(
        ventas  = find_col(ws,1,'VENTA'),
        costo   = find_col(ws,1,'COSTO'),
        util_b  = find_col(ws,1,'UTILIDAD BRUTA'),
        gop     = find_col(ws,1,'GASTOS'),
    )
    COLORS = ['#0ea87a','#5b5ef4','#e8620a','#d49600','#e8334a',
              '#0891b2','#a259ff','#f7794f','#65a30d','#7c3aed',
              '#22c55e','#0369a1','#be185d','#92400e']
    out, ci = [], 0
    for row in ws.iter_rows(min_row=2, values_only=True):
        nombre = str(row[0]).strip() if row[0] else None
        if not nombre or nombre.upper() in ('TOTAL','NONE',''): continue
        def v(k): return round((row[cols[k]-1] or 0)/1e6, 1) if cols[k] else 0.0
        out.append(dict(name=nombre, ventas=v('ventas'), costo=v('costo'),
                        ub=v('util_b'), gop=v('gop'), color=COLORS[ci % len(COLORS)]))
        ci += 1
    out.sort(key=lambda c: c['ventas'], reverse=True)
    return out

# ─── HELPERS ─────────────────────────────────────────────────────────────────

def jsa(lst):
    def fmt(x): return json.dumps(x) if isinstance(x, str) else str(x)
    return '[' + ','.join(fmt(x) for x in lst) + ']'

def jscanales(canales):
    rows = [
        '{' + f"name:{json.dumps(c['name'])},ventas:{c['ventas']},costo:{c['costo']},"
        f"ub:{c['ub']},gop:{c['gop']},color:{json.dumps(c['color'])}" + '}'
        for c in canales
    ]
    return '[\n  ' + ',\n  '.join(rows) + '\n]'

def sf(v):
    sign = '-$' if v < 0 else '$'
    s = f"{abs(v):,.1f}".replace(',','X').replace('.',',').replace('X','.')
    return sign + s + ' M'

def leer_tiendas(wb):
    ws = next((wb[n] for n in wb.sheetnames if 'TIEND' in n.upper()), None)
    if not ws: return []
    COLORS = ['#0ea87a','#5b5ef4','#e8620a','#d49600','#e8334a',
              '#0891b2','#a259ff','#f7794f','#65a30d','#7c3aed',
              '#22c55e','#0369a1','#be185d','#92400e','#e8620a',
              '#d49600','#0ea87a','#5b5ef4','#e8334a','#a259ff',
              '#f7794f','#65a30d','#7c3aed','#22c55e','#0369a1',
              '#be185d','#92400e','#0891b2','#e8620a','#d49600']
    tiendas = []
    ci = 0
    for row in ws.iter_rows(min_row=2, values_only=True):
        nombre = str(row[0]).strip() if row[0] else None
        if not nombre or nombre.upper() == 'TOTAL': continue
        ingresos = round((row[1] or 0) / 1_000_000, 1)
        costo    = round((row[2] or 0) / 1_000_000, 1)
        util_b   = round((row[3] or 0) / 1_000_000, 1)
        pct_ub   = round((row[4] or 0) * 100, 1)
        gasto    = round((row[5] or 0) / 1_000_000, 1)
        sin_arr  = round((row[6] or 0) / 1_000_000, 1)
        util_op  = round((row[7] or 0) / 1_000_000, 1)
        ebitda   = round((row[8] or 0) * 100, 1)
        tiendas.append({
            'name': nombre, 'color': COLORS[ci % len(COLORS)],
            'ingresos': ingresos, 'costo': costo,
            'util_b': util_b, 'pct_ub': pct_ub,
            'gasto': gasto, 'sin_arr': sin_arr,
            'util_op': util_op, 'ebitda': ebitda
        })
        ci += 1
    # ordenar por ingresos desc
    tiendas.sort(key=lambda x: x['ingresos'], reverse=True)
    return tiendas

def calcular(pyg, ppto):
    tv = sum(pyg['ventas']); tc = sum(pyg['costo']); tub = sum(pyg['util_b'])
    tgo = sum(pyg['gastos_op']); tgn = sum(pyg['gtos_no'])
    tuo = tub - tgo; tua = tuo + tgn; tp = sum(ppto)
    cumpl = round(tv/tp*100,1) if tp else 0
    return dict(tv=round(tv,1), tc=round(tc,1), tub=round(tub,1),
                tgo=round(tgo,1), tgn=round(tgn,1), tuo=round(tuo,1),
                tua=round(tua,1), tp=round(tp,1), cumpl=cumpl,
                brecha=round(tv-tp,1),
                mgb=round(tub/tv*100,1) if tv else 0,
                mgo=round(tuo/tv*100,1) if tv else 0)

# ─── GENERADOR HTML ───────────────────────────────────────────────────────────

def js_tiendas_data(tiendas):
    """Serializa lista de tiendas a array JS."""
    import json
    return json.dumps([{
        'name':  t['name'],
        'color': t['color'],
        'ingresos': t['ingresos'],
        'costo':    t['costo'],
        'util_b':   t['util_b'],
        'pct_ub':   t['pct_ub'],
        'gasto':    t['gasto'],
        'sin_arr':  t['sin_arr'],
        'util_op':  t['util_op'],
        'ebitda':   t['ebitda'],
    } for t in tiendas], ensure_ascii=False)

def generar_html(pyg, ppto, canales, tiendas, empresa, moneda, logo_html=''):
    """Genera el HTML del dashboard inyectando datos en la plantilla."""
    import json, base64

    t = calcular(pyg, ppto)
    n = len(pyg['meses'])

    util_op  = [round(pyg['util_b'][i] - pyg['gastos_op'][i], 1) for i in range(n)]
    util_ant = [round(util_op[i] + pyg['gtos_no'][i], 1) for i in range(n)]
    var_ppto      = [round(pyg['ventas'][i] - ppto[i], 1) for i in range(n)]
    var_mens      = [0.0] + [round(pyg['ventas'][i]-pyg['ventas'][i-1],1) for i in range(1,n)]
    var_acum      = [round(sum(pyg['ventas'][:i+1]) - sum(ppto[:i+1]), 1) for i in range(n)]
    var_ppto_mens = [round(ppto[i] - (ppto[i-1] if i>0 else 0), 1) for i in range(n)]

    def jsl(lst):  return json.dumps([round(float(x),1) for x in lst])
    def jss(lst):  return json.dumps(list(lst))
    def pct(a,b):  return round(a/b*100,1) if b else 0.0

    # ── Tiendas arrays ────────────────────────────────────────────────────────
    tN   = [t2['name']     for t2 in tiendas]
    tIng = [t2['ingresos'] for t2 in tiendas]
    tUB_ = [t2['ub']       for t2 in tiendas]
    tUO_ = [t2['uo']       for t2 in tiendas]
    tPct_= [t2['margen']   for t2 in tiendas]
    tEb_ = [t2['ebitda']   for t2 in tiendas]
    tGas = [t2['gastos']   for t2 in tiendas]
    tUOColors = [('rgba(14,168,122,.75)' if v>=0 else 'rgba(232,51,74,.70)') for v in tUO_]
    tUOBorder = [('#0ea87a' if v>=0 else '#e8334a') for v in tUO_]
    PIE_COLORS = ["#0ea87a","#5b5ef4","#e8620a","#d49600","#e8334a","#0891b2","#a259ff",
                  "#f7794f","#65a30d","#7c3aed","#22c55e","#0369a1","#be185d","#92400e",
                  "#06b6d4","#84cc16","#f59e0b","#ec4899","#14b8a6","#8b5cf6","#f97316",
                  "#10b981","#6366f1","#ef4444","#eab308","#3b82f6","#a3e635","#fb7185",
                  "#34d399","#c084fc"]

    # ── Canales JS ────────────────────────────────────────────────────────────
    canal_rows = []
    for ch in canales:
        canal_rows.append(
            f'  {{name:{json.dumps(ch["name"])},ventas:{ch["ventas"]},costo:{ch["costo"]},'
            f'ub:{ch["ub"]},gop:{ch["gop"]},color:{json.dumps(ch["color"])}}}'
        )
    canales_js = 'const canales  = [\n' + ',\n'.join(canal_rows) + '\n];'

    # ── PYG table rows ────────────────────────────────────────────────────────
    pyg_rows = []
    for i in range(n):
        uo_i = util_op[i]; ua_i = util_ant[i]
        pyg_rows.append(
            f'<tr><td>{pyg["meses"][i]}</td>'
            f'<td>${pyg["ventas"][i]:.1f} M</td>'
            f'<td>${pyg["costo"][i]:.1f} M</td>'
            f'<td>${pyg["util_b"][i]:.1f} M</td>'
            f'<td>{pct(pyg["util_b"][i],pyg["ventas"][i]):.1f}%</td>'
            f'<td>${pyg["gastos_op"][i]:.1f} M</td>'
            f'<td class="{"pos" if uo_i>=0 else "neg"}">${uo_i:.1f} M</td>'
            f'<td class="{"pos" if ua_i>=0 else "neg"}">${ua_i:.1f} M</td></tr>'
        )
    pyg_table = '\n'.join(pyg_rows)

    # ── Data JS block ─────────────────────────────────────────────────────────
    data_js = f"""const meses    = {jss(pyg['meses'])};
const ventas   = {jsl(pyg['ventas'])};
const costo    = {jsl(pyg['costo'])};
const utilB    = {jsl(pyg['util_b'])};
const gastosOp = {jsl(pyg['gastos_op'])};
const gtosNo   = {jsl(pyg['gtos_no'])};
const ppto     = {jsl(ppto)};
const utilOp   = {jsl(util_op)};
const utilAnt  = {jsl(util_ant)};
const varVsPpto     = {jsl(var_ppto)};
const varMensual    = {jsl(var_mens)};
const varAcum       = {jsl(var_acum)};
const varPptoMens   = {jsl(var_ppto_mens)};
const costoTotal    = {round(sum(pyg['ventas']),1)};

{canales_js}

// ── TIENDAS DATA ──────────────────────────────────────────────────────────────
const tNombres   = {json.dumps(tN)};
const tIng       = {jsl(tIng)};
const tUB        = {jsl(tUB_)};
const tUO        = {jsl(tUO_)};
const tPct       = {jsl(tPct_)};
const tEbitda    = {jsl(tEb_)};
const tGastos    = {jsl(tGas)};
const tUOColors  = {json.dumps(tUOColors)};
const tUOBorder  = {json.dumps(tUOBorder)};
const tPieColors = {json.dumps(PIE_COLORS)};

"""

    # ── Assemble using embedded template ─────────────────────────────────────
    HTML_BEFORE = base64.b64decode('').decode()
    HTML_AFTER  = base64.b64decode('').decode()

    out = HTML_BEFORE + data_js + HTML_AFTER

    # Replace company name and logo
    out = out.replace('>ABC Consulting<', f'>{empresa}<', 1)
    out = out.replace('<title>ABC Consulting</title>', f'<title>{empresa}</title>', 1)
    if logo_html:
        out = out.replace('id="logoArea">', f'id="logoArea">{logo_html}', 1)

    # Replace PYG table rows
    out = out.replace('id="pygTblBody"></tbody>', f'id="pygTblBody">{pyg_table}</tbody>', 1)

    return out


def main():
    parser = argparse.ArgumentParser(description='Genera dashboard HTML desde Excel.')
    parser.add_argument('excel', nargs='?', default='informacion_analisis_empresa_A.xlsx')
    parser.add_argument('-o','--output', default=None)
    parser.add_argument('-n','--nombre', default=None)
    parser.add_argument('-m','--moneda', default='COP')
    parser.add_argument('-l','--logo', default=None, help='Ruta a imagen del logo (PNG/JPG/SVG)')
    args = parser.parse_args()

    excel_path = Path(args.excel)
    if not excel_path.exists():
        print(f"❌ No se encontró: {excel_path}"); sys.exit(1)

    empresa = args.nombre or excel_path.stem.replace('_',' ').replace('-',' ').title()
    output  = Path(args.output) if args.output else Path(f"dashboard_{empresa.replace(' ','_')}.html")

    print(f"\n{'─'*52}")
    print(f"  📊  {empresa}  ·  {args.moneda}")
    print(f"  📁  {excel_path}  →  {output}")
    print(f"{'─'*52}\n")

    wb = openpyxl.load_workbook(str(excel_path), data_only=True)
    print("⏳ Leyendo Excel...")
    pyg = leer_pyg(wb)
    print(f"   ✅ PYG: {len(pyg['meses'])} meses ({', '.join(pyg['meses'])})")
    ppto = leer_ppto(wb, pyg)
    print(f"   ✅ Presupuesto: {len(ppto)} valores")
    canales = leer_canales(wb)
    print(f"   ✅ Canales: {len(canales)} ({', '.join(c['name'] for c in canales)})")
    tiendas = leer_tiendas(wb)
    print(f"   ✅ Tiendas: {len(tiendas)}")

    t = calcular(pyg, ppto)
    print(f"\n📈 Ventas {sf(t['tv'])} | UB {sf(t['tub'])} ({t['mgb']}%) | Cumpl {t['cumpl']}%\n")

    # Logo: embed as base64 if provided
    logo_html = ''
    if args.logo:
        logo_path = Path(args.logo)
        if logo_path.exists():
            import base64, mimetypes
            mime = mimetypes.guess_type(str(logo_path))[0] or 'image/png'
            b64  = base64.b64encode(logo_path.read_bytes()).decode()
            logo_html = f'<img src="data:{mime};base64,{b64}" alt="{empresa}" style="height:36px;width:auto;vertical-align:middle;margin-right:10px">'
        else:
            print(f"⚠️  Logo no encontrado: {args.logo}")

    html = generar_html(pyg, ppto, canales, tiendas, empresa, args.moneda, logo_html)
    output.write_text(html, encoding='utf-8')
    print(f"✅ Dashboard generado: {output}  ({output.stat().st_size//1024} KB)")
    print(f"\n🚀  Abre en tu navegador: {output.resolve()}\n")

if __name__ == '__main__':
    main()
